text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "decision": "공개 릴리스 목표는 금요일 15:00 KST로 잡되, smoke 테스트 통과가 전제 조건이다.",
        "certainty": "confirmed"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 재검토한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "status": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 릴리스를 검토하자는 제안이 있었지만 최종 목표는 아니며, 내부 stretch goal로만 남았다.",
        "status": "stretch_goal"
      },
      {
        "item": "README 설치 단계를 목요일까지 검토하면 좋겠다는 의견이 있었으나 담당자는 지정되지 않았다.",
        "status": "unassigned_note"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다.",
        "severity": "not_specified"
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있다.",
        "severity": "not_specified"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한은 누구에게 있는가?",
      "릴리스 노트에 내부 수요일 stretch goal을 명시해야 하는가?"
    ],
    "non_decisions": [
      "수요일 릴리스는 논의되었지만 최종 결정되지 않았고, 공개 릴리스 목표로 채택되지 않았다.",
      "README 설치 단계 검토는 필요성이 언급되었지만 소유자와 확정 일정이 정해지지 않았다."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed_followup",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 smoke 테스트 결과",
      "생성된 tarball 경로",
      "packageName 불일치가 패키지 설정 문제인지 계약 문제인지",
      "최종 릴리스 승인 권한",
      "README 설치 단계의 최신성 여부",
      "릴리스 노트에 내부 수요일 stretch goal을 포함할지 여부"
    ],
    "what_not_to_invent": [
      "고객명",
      "외부 파트너명",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법적 승인 요구사항",
      "확정되지 않은 소유자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "고객 또는 외부 파트너는 특정하지 않는다.",
    "예산, 보안 사고, 프로덕션 장애, 법적 승인 요구사항은 언급하지 않는다.",
    "소유자가 지정되지 않은 항목은 임의 배정하지 않는다.",
    "명시되지 않은 마감일은 만들지 않는다.",
    "확정되지 않은 결정은 confirmed로 표시하지 않는다.",
    "제공된 synthetic fixture 밖의 사실은 추론하거나 보강하지 않는다."
  ]
}
